<?php $__env->startSection('content'); ?><h1 class="text-3xl font-bold">Verifikasi Donasi Manual</h1><div class="mt-6 space-y-4"><?php $__currentLoopData = $donations; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $donation): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><div class="card"><div class="grid gap-4 md:grid-cols-3"><div><p class="font-bold"><?php echo e($donation->donor_name); ?></p><p class="text-sm text-slate-600"><?php echo e($donation->campaign->title); ?></p><p class="font-semibold text-brand-700">Rp <?php echo e(number_format($donation->amount,0,',','.')); ?></p></div><div class="text-sm"><p>Bank: <?php echo e($donation->proof->bank_name); ?></p><p>Rekening: <?php echo e($donation->proof->account_name); ?></p><a class="text-brand-700" href="<?php echo e(Storage::url($donation->proof->file_path)); ?>" target="_blank">Lihat bukti transfer</a></div><form method="post" action="<?php echo e(route('admin.donations.verify',$donation)); ?>" class="space-y-2"><?php echo csrf_field(); ?> <?php echo method_field('patch'); ?><textarea class="input" name="admin_notes" placeholder="Catatan admin"></textarea><div class="flex gap-2"><button class="btn-primary flex-1" name="action" value="approve">Approve</button><button class="btn-secondary flex-1" name="action" value="reject">Reject</button></div></form></div></div><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></div><div class="mt-6"><?php echo e($donations->links()); ?></div><?php $__env->stopSection(); ?>

